mcqs.question:
What is the output of the following code?
int x = 2;
switch(x) {
    case 1: printf("One ");
    case 2: printf("Two ");
    case 3: printf("Three ");
    default: printf("Default");
}

What will be the output?
char grade = 'B';
switch(grade) {
    case 'A': printf("Excellent"); break;
    case 'B': printf("Good"); break;
    case 'C': printf("Average"); break;
    default: printf("Invalid");
}

What is the output of this code?
int num = 0;
switch(num) {
    default: printf("Default ");
    case 1: printf("One ");
    case 2: printf("Two ");
}

What is the output?
int day = 3;
switch(day) {
    case 1: printf("Monday"); break;
    case 2: printf("Tuesday"); break;
    case 3: printf("Wednesday"); break;
    case 4: printf("Thursday"); break;
}

What is the output?
int x = 5;
switch(x) {
    case 5: printf("A");
    case 4: printf("B");
    default: printf("C");
}

What will be printed?
int n = 10;
switch(n) {
    case 10: printf("Ten ");
    case 20: printf("Twenty ");
    case 30: printf("Thirty ");
    break;
    default: printf("Other");
}

What is the output?
char ch = 'C';
switch(ch + 1) {
    case 'D': printf("1"); break;
    case 'E': printf("2"); break;
    default: printf("0");
}
